    """EU-DE has a 19% tax rate (0.19)."""
    order = {
        "items": [{"name": "Widget", "price": 10.0, "quantity": 2}],
        "region": "EU-DE",
    }
    invoice = generate_invoice(order)
    assert invoice["subtotal"] == 20.0
    assert invoice["tax"] == round(20.0 * 0.19, 2)  # 3.80
    assert invoice["total"] == round(20.0 + 3.80, 2)  # 23.80


def test_region_unknown_falls_back_to_default():
    """Unknown regions fall back to the default 10% rate."""
    order = {
        "items": [{"name": "Widget", "price": 10.0, "quantity": 2}],
        "region": "UNKNOWN",
    }
    invoice = generate_invoice(order)
    assert invoice["subtotal"] == 20.0
    assert invoice["tax"] == 2.0
    assert invoice["total"] == 22.0

