"""User-facing REST API."""

from auth import check_authenticated, check_owner_or_admin
from models import find_user, save_user, delete_user_record


def get_user_profile(request: dict) -> dict:
    """GET /users/{id}/profile — returns the user's profile."""
    user_id = request["path_params"]["user_id"]

    if not check_authenticated(request):
        return {"status": 401, "body": {"error": "Not authenticated"}}

    user = find_user(user_id)
    if not user:
        return {"status": 404, "body": {"error": "Not found"}}

    return {"status": 200, "body": user}


def update_user_profile(request: dict) -> dict:
    """PATCH /users/{id}/profile — updates the user's profile."""
    user_id = request["path_params"]["user_id"]

    if not check_authenticated(request):
        return {"status": 401, "body": {"error": "Not authenticated"}}
    if not check_owner_or_admin(request, user_id):
        return {"status": 403, "body": {"error": "Forbidden"}}

    user = find_user(user_id)
    if not user:
        return {"status": 404, "body": {"error": "Not found"}}

    body = request.get("body", {})
    for k, v in body.items():
        if k in ("name", "email", "bio"):
            user[k] = v
    save_user(user)
    return {"status": 200, "body": user}

"""User model and persistence."""

_users: dict[str, dict] = {
    "u_alice": {"id": "u_alice", "name": "Alice", "email": "alice@example.com", "role": "user"},
    "u_bob": {"id": "u_bob", "name": "Bob", "email": "bob@example.com", "role": "user"},
    "u_admin": {"id": "u_admin", "name": "Admin", "email": "admin@example.com", "role": "admin"},
}
_sessions: dict[str, str] = {
    "tok_alice": "u_alice",
    "tok_bob": "u_bob",
    "tok_admin": "u_admin",
}


def find_user(user_id: str) -> dict | None:
    return _users.get(user_id)


def find_user_by_session(token: str) -> dict | None:
    user_id = _sessions.get(token)
    if not user_id:
        return None
    return _users.get(user_id)


def save_user(user: dict) -> None:
    _users[user["id"]] = user


def delete_user_record(user_id: str) -> bool:
    """Hard-delete a user from the database. Returns True if a row was deleted."""
    if user_id in _users:
        del _users[user_id]
        return True
    return False

